 6→export async function GET(request: NextRequest) {
 7→  try {
 8→    const userId = await getAuthenticatedUserId();
 9→    const categoryId = request.nextUrl.searchParams.get("categoryId");
10→
11→    const tags = await prisma.categoryTag.findMany({
12→      where: {
13→        userId,
14→        ...(categoryId ? { categoryId } : {}),
15→      },
16→      include: { category: true },
17→      orderBy: { name: "asc" },
18→    });
19→
20→    return NextResponse.json(tags);
21→  } catch (error) {
22→    if (error instanceof Error && error.message === "Unauthorized") {
23→      return unauthorizedResponse();
24→    }
25→    console.error("Error fetching category tags:", error);
26→    return NextResponse.json(
27→      { error: "Erro ao buscar tags de categoria" },
28→      { status: 500 }
29→    );
30→  }
31→}
