 9→) {
10→  try {
11→    const userId = await getAuthenticatedUserId();
12→    const { id } = await params;
13→    const body = await request.json();
14→    const { name, keywords } = body;
15→
16→    if (!name && !keywords) {
17→      return NextResponse.json(
18→        { error: "Informe name ou keywords para atualizar" },
19→        { status: 400 }
20→      );
21→    }
22→
23→    // Verify tag belongs to user
24→    const existing = await prisma.categoryTag.findFirst({
25→      where: { id, userId },
26→    });
27→
28→    if (!existing) {
29→      return NextResponse.json(
30→        { error: "Tag não encontrada" },
31→        { status: 404 }
32→      );
33→    }
34→
35→    const data: { name?: string; keywords?: string } = {};
36→    if (name) data.name = name;
37→    if (keywords) data.keywords = keywords.toLowerCase();
38→
39→    const tag = await prisma.categoryTag.update({
40→      where: { id },
41→      data,
42→      include: { category: true },
43→    });
44→
45→    invalidateTagsCache();
46→
47→    return NextResponse.json(tag);
