  1→import { NextRequest, NextResponse } from "next/server";
  2→import prisma from "@/lib/db";
  3→import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
  4→
  5→export async function GET(request: NextRequest) {
  6→  try {
  7→    const userId = await getAuthenticatedUserId();
  8→    const searchParams = request.nextUrl.searchParams;
  9→    const month = searchParams.get("month");
 10→    const year = searchParams.get("year");
 11→    const startDate = searchParams.get("startDate");
 12→    const endDate = searchParams.get("endDate");
 13→    const categoryId = searchParams.get("categoryId");
 14→    const origin = searchParams.get("origin");
 15→    const type = searchParams.get("type");
 16→    const isFixed = searchParams.get("isFixed");
 17→    const isInstallment = searchParams.get("isInstallment");
 18→    const search = searchParams.get("search");
 19→    const tag = searchParams.get("tag");
 20→    const includeDeleted = searchParams.get("includeDeleted");
 21→
 22→    const where: Record<string, unknown> = {
 23→      userId,
 24→    };
 25→
 26→    // By default, exclude soft-deleted transactions
 27→    if (includeDeleted !== "true") {
 28→      where.deletedAt = null;
 29→    }
 30→
 31→    // Custom date range filter takes priority
 32→    if (startDate && endDate) {
 33→      where.date = {
 34→        gte: new Date(startDate),
 35→        lte: new Date(endDate),
 36→      };
 37→    } else if (month && year) {
 38→      const monthStart = new Date(parseInt(year), parseInt(month) - 1, 1);
 39→      const monthEnd = new Date(parseInt(year), parseInt(month), 0);
 40→      where.date = {
 41→        gte: monthStart,
 42→        lte: monthEnd,
 43→      };
 44→    } else if (year) {
 45→      const yearStart = new Date(parseInt(year), 0, 1);
 46→      const yearEnd = new Date(parseInt(year), 11, 31);
 47→      where.date = {
 48→        gte: yearStart,
 49→        lte: yearEnd,
 50→      };
 51→    }
 52→
 53→    // Global text search
 54→    if (search && search.trim()) {
 55→      where.description = {
 56→        contains: search.trim(),
 57→      };
 58→    }
 59→
 60→    if (categoryId) {
 61→      where.categoryId = categoryId;
 62→    }
 63→
 64→    if (origin) {
 65→      where.origin = origin;
 66→    }
 67→
 68→    if (type) {
 69→      where.type = type;
 70→    }
 71→
 72→    if (isFixed === "true") {
 73→      where.isFixed = true;
 74→    }
 75→
 76→    if (isInstallment === "true") {
 77→      where.isInstallment = true;
 78→    }
 79→
 80→    // Filter standalone installments (not linked to an Installment group)
 81→    const standalone = searchParams.get("standalone");
 82→    if (standalone === "true") {
 83→      where.installmentId = null;
 84→    }
 85→
 86→    // Filter by tag (searches within JSON array string)
 87→    if (tag && tag.trim()) {
 88→      where.tags = {
 89→        contains: tag.trim(),
 90→      };
 91→    }
 92→
 93→    const transactions = await prisma.transaction.findMany({
 94→      where,
 95→      include: {
 96→        category: true,
 97→        categoryTag: true,
 98→        installment: true,
 99→      },
100→      orderBy: {
101→        date: "desc",
102→      },
103→    });
104→
105→    return NextResponse.json(transactions);
106→  } catch (error) {
107→    if (error instanceof Error && error.message === "Unauthorized") {
108→      return unauthorizedResponse();
109→    }
110→    console.error("Error fetching transactions:", error);
111→    return NextResponse.json(
112→      { error: "Erro ao buscar transacoes" },
113→      { status: 500 }
114→    );
115→  }
116→}
