 83→  async function fetchData() {
 84→    try {
 85→      setLoading(true);
 86→      const params = new URLSearchParams();
 87→      if (filterStartDate) params.set("startDate", filterStartDate);
 88→      if (filterEndDate) params.set("endDate", filterEndDate);
 89→      if (filterCategory && filterCategory !== "all") params.set("categoryId", filterCategory);
 90→      if (filterType && filterType !== "all") params.set("type", filterType);
 91→      if (filterFixed) params.set("isFixed", "true");
 92→      if (filterInstallment) params.set("isInstallment", "true");
 93→      if (filterOrigin && filterOrigin !== "all") params.set("origin", filterOrigin);
 94→      if (searchQuery) params.set("search", searchQuery);
 95→      if (filterTag) params.set("tag", filterTag);
 96→
 97→      const res = await fetch(`/api/transactions?${params.toString()}`);
 98→      const data = await res.json();
 99→      setTransactions(data);
100→
101→      // Extract unique tags from all transactions
102→      const tagsSet = new Set<string>();
103→      data.forEach((t: Transaction) => {
104→        if (t.tags) {
105→          try {
106→            const parsedTags = JSON.parse(t.tags);
107→            parsedTags.forEach((tag: string) => tagsSet.add(tag));
108→          } catch {
109→            // Ignore parsing errors
110→          }
111→        }
112→      });
113→      setAllTags(Array.from(tagsSet).sort());
114→    } catch (error) {
115→      console.error("Error fetching transactions:", error);
116→    } finally {
117→      setLoading(false);
118→    }
119→  }
