240→  // Group transactions by date range
241→  function groupTransactionsByDateRange(txs: Transaction[]) {
242→    const now = new Date();
243→    const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
244→    const yesterday = new Date(today);
245→    yesterday.setDate(yesterday.getDate() - 1);
246→    const weekStart = new Date(today);
247→    weekStart.setDate(weekStart.getDate() - today.getDay());
248→    const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);
249→    const lastMonthStart = new Date(now.getFullYear(), now.getMonth() - 1, 1);
250→    const lastMonthEnd = new Date(now.getFullYear(), now.getMonth(), 0);
251→
252→    const groups: { label: string; transactions: Transaction[] }[] = [
253→      { label: "Hoje", transactions: [] },
254→      { label: "Ontem", transactions: [] },
255→      { label: "Esta semana", transactions: [] },
256→      { label: "Este mês", transactions: [] },
257→      { label: "Mês passado", transactions: [] },
258→      { label: "Anteriores", transactions: [] },
259→    ];
260→
261→    txs.forEach((t) => {
262→      const date = new Date(t.date);
263→      const txDate = new Date(date.getFullYear(), date.getMonth(), date.getDate());
264→
265→      if (txDate.getTime() === today.getTime()) {
266→        groups[0].transactions.push(t);
267→      } else if (txDate.getTime() === yesterday.getTime()) {
268→        groups[1].transactions.push(t);
269→      } else if (txDate >= weekStart && txDate < yesterday) {
270→        groups[2].transactions.push(t);
271→      } else if (txDate >= monthStart && txDate < weekStart) {
272→        groups[3].transactions.push(t);
273→      } else if (txDate >= lastMonthStart && txDate <= lastMonthEnd) {
274→        groups[4].transactions.push(t);
275→      } else {
276→        groups[5].transactions.push(t);
277→      }
278→    });
279→
280→    return groups.filter((g) => g.transactions.length > 0);
281→  }
