 59→export async function GET(request: NextRequest) {
 60→  try {
 61→    const userId = await getAuthenticatedUserId();
 62→
 63→    const searchParams = request.nextUrl.searchParams;
 64→    const closingDay = parseInt(searchParams.get("closingDay") || "13");
 65→    const origin = searchParams.get("origin"); // Optional: filter by card/origin
 66→
 67→    // Get bill periods (last 6 months)
 68→    const periods = getBillPeriods(closingDay, 6);
 69→
 70→    // Fetch transactions for each period
 71→    const bills = await Promise.all(
 72→      periods.map(async (period) => {
 73→        const where: Record<string, unknown> = {
 74→          userId,
 75→          date: {
 76→            gte: period.startDate,
 77→            lte: period.endDate,
 78→          },
 79→          deletedAt: null,
 80→          type: "EXPENSE", // Only expenses for bills
 81→          investmentTransaction: null,
 82→        };
 83→
 84→        if (origin) {
 85→          where.origin = origin;
 86→        }
 87→
 88→        const transactions = await prisma.transaction.findMany({
 89→          where,
 90→          include: {
 91→            category: true,
 92→          },
 93→          orderBy: {
 94→            date: "desc",
 95→          },
 96→        });
 97→
 98→        // Calculate transaction total (only period transactions)
 99→        const transactionTotal = transactions.reduce(
100→          (sum, t) => sum + Math.abs(t.amount),
101→          0
102→        );
103→
104→        // Look for carryover from previous month's bill payment
105→        // Calculate previous month (handle January -> December of previous year)
106→        const prevMonth = period.month === 1 ? 12 : period.month - 1;
107→        const prevYear = period.month === 1 ? period.year - 1 : period.year;
108→
109→        // Query for partial bill payments from the previous month
110→        const carryoverQuery: Record<string, unknown> = {
111→          userId,
112→          billMonth: prevMonth,
113→          billYear: prevYear,
114→          paymentType: "PARTIAL",
115→          amountCarried: { gt: 0 },
116→        };
117→
118→        if (origin) {
119→          carryoverQuery.origin = origin;
120→        }
121→
122→        const carryoverPayment = await prisma.billPayment.findFirst({
123→          where: carryoverQuery,
124→        });
125→
126→        // Build carryover info if found
127→        let carryover: CarryoverInfo | null = null;
128→        let carryoverAmount = 0;
129→        let interestAmount = 0;
130→
131→        if (carryoverPayment) {
132→          carryoverAmount = carryoverPayment.amountCarried;
133→          interestAmount = carryoverPayment.interestAmount || 0;
134→
135→          const monthNames = [
136→            "Janeiro", "Fevereiro", "Marco", "Abril", "Maio", "Junho",
137→            "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"
138→          ];
139→
140→          carryover = {
141→            amount: carryoverAmount,
142→            interest: interestAmount,
143→            fromBill: `${monthNames[prevMonth - 1]}/${prevYear}`,
144→            billPaymentId: carryoverPayment.id,
145→          };
146→        }
147→
148→        // Total includes transaction total + carryover + interest
149→        const total = transactionTotal + carryoverAmount + interestAmount;
150→
151→        // Group by category
152→        const categoryTotals: Record<
153→          string,
154→          { name: string; color: string; total: number; count: number }
155→        > = {};
156→
157→        for (const t of transactions) {
158→          const catId = t.categoryId || "uncategorized";
159→          const catName = t.category?.name || "Sem categoria";
160→          const catColor = t.category?.color || "#9CA3AF";
161→
162→          if (!categoryTotals[catId]) {
163→            categoryTotals[catId] = {
164→              name: catName,
165→              color: catColor,
166→              total: 0,
167→              count: 0,
168→            };
169→          }
170→          categoryTotals[catId].total += Math.abs(t.amount);
171→          categoryTotals[catId].count++;
172→        }
173→
174→        const categories = Object.entries(categoryTotals)
175→          .map(([id, data]) => ({
176→            id,
177→            ...data,
178→            percentage: total > 0 ? (data.total / total) * 100 : 0,
179→          }))
180→          .sort((a, b) => b.total - a.total);
181→
182→        return {
183→          label: period.label,
184→          month: period.month,
185→          year: period.year,
186→          startDate: period.startDate.toISOString(),
187→          endDate: period.endDate.toISOString(),
188→          dueDate: period.dueDate.toISOString(),
189→          total,
190→          transactionTotal,
191→          carryover,
192→          transactionCount: transactions.length,
193→          categories,
194→          transactions: transactions.map((t) => ({
195→            id: t.id,
196→            description: t.description,
197→            amount: t.amount,
198→            date: t.date.toISOString(),
199→            origin: t.origin,
200→            categoryId: t.categoryId,
201→            categoryName: t.category?.name || "Sem categoria",
202→            categoryColor: t.category?.color || "#9CA3AF",
203→            isInstallment: t.isInstallment,
204→            currentInstallment: t.currentInstallment,
205→          })),
206→        };
207→      })
208→    );
209→
210→    // Get available origins for filtering
211→    const origins = await prisma.origin.findMany({
212→      where: { userId },
213→      orderBy: { name: "asc" },
214→    });
215→
216→    // Calculate comparison with previous bill
217→    const billsWithComparison = bills.map((bill, index) => {
218→      const previousBill = bills[index + 1];
219→      const changePercentage = previousBill
220→        ? ((bill.total - previousBill.total) / previousBill.total) * 100
221→        : null;
222→
223→      return {
224→        ...bill,
225→        previousTotal: previousBill?.total || null,
226→        changePercentage,
227→      };
228→    });
229→
230→    return NextResponse.json({
231→      closingDay,
232→      bills: billsWithComparison,
233→      origins,
234→    });
235→  } catch (error) {
236→    if (error instanceof Error && error.message === "Unauthorized") {
237→      return unauthorizedResponse();
238→    }
239→    console.error("Error fetching bills:", error);
240→    return NextResponse.json(
241→      { error: "Erro ao buscar faturas" },
242→      { status: 500 }
243→    );
244→  }
245→}
