  4→interface RuleWithCategory extends CategoryRule {
  5→  category: Category;
  6→}
  7→
  8→// Cache rules per user
  9→const rulesCacheByUser: Map<string, RuleWithCategory[]> = new Map();
 10→
 11→export async function getRules(userId?: string): Promise<RuleWithCategory[]> {
 12→  const cacheKey = userId || "_global";
 13→  const cached = rulesCacheByUser.get(cacheKey);
 14→  if (cached) return cached;
 15→
 16→  const rules = await prisma.categoryRule.findMany({
 17→    where: userId ? { userId } : undefined,
 18→    include: { category: true },
 19→  });
 20→
 21→  rulesCacheByUser.set(cacheKey, rules as RuleWithCategory[]);
 22→  return rules as RuleWithCategory[];
 23→}
 24→
 25→export function invalidateRulesCache(userId?: string) {
 26→  if (userId) {
 27→    rulesCacheByUser.delete(userId);
 28→  } else {
 29→    rulesCacheByUser.clear();
 30→  }
 31→}
 32→
 33→// Cache category tags per user
 34→interface TagWithCategory {
 35→  id: string;
 36→  name: string;
 37→  keywords: string;
 38→  categoryId: string;
 39→  category: Category;
 40→}
 41→
 42→const tagsCacheByUser: Map<string, TagWithCategory[]> = new Map();
 43→
 44→export async function getCategoryTags(userId?: string): Promise<TagWithCategory[]> {
 45→  const cacheKey = userId || "_global";
 46→  const cached = tagsCacheByUser.get(cacheKey);
 47→  if (cached) return cached;
 48→
 49→  const tags = await prisma.categoryTag.findMany({
 50→    where: userId ? { userId } : undefined,
 51→    include: { category: true },
 52→  });
 53→
 54→  tagsCacheByUser.set(cacheKey, tags as TagWithCategory[]);
 55→  return tags as TagWithCategory[];
 56→}
 57→
 58→export function invalidateTagsCache(userId?: string) {
 59→  if (userId) {
 60→    tagsCacheByUser.delete(userId);
 61→  } else {
 62→    tagsCacheByUser.clear();
 63→  }
 64→}
