 66→export async function matchCategoryTag(
 67→  description: string,
 68→  categoryId: string,
 69→  userId?: string
 70→): Promise<TagWithCategory | null> {
 71→  const allTags = await getCategoryTags(userId);
 72→  const categoryTags = allTags.filter((t) => t.categoryId === categoryId);
 73→
 74→  if (categoryTags.length === 0) return null;
 75→
 76→  const upperDesc = description.toUpperCase();
 77→  const matches: TagWithCategory[] = [];
 78→
 79→  for (const tag of categoryTags) {
 80→    const keywords = tag.keywords.split(",").map((k) => k.trim().toUpperCase()).filter((k) => k.length > 0);
 81→    const hasMatch = keywords.some((keyword) => upperDesc.includes(keyword));
 82→    if (hasMatch) {
 83→      matches.push(tag);
 84→    }
 85→  }
 86→
 87→  // Conservative: only return if exactly one tag matches
 88→  if (matches.length === 1) {
 89→    return matches[0];
 90→  }
 91→
 92→  return null;
 93→}
