 95→export async function suggestCategory(
 96→  description: string,
 97→  userId?: string
 98→): Promise<Category | null> {
 99→  const rules = await getRules(userId);
100→  const upperDesc = description.toUpperCase();
101→
102→  for (const rule of rules) {
103→    if (upperDesc.includes(rule.keyword.toUpperCase())) {
104→      return rule.category;
105→    }
106→  }
107→
108→  return null;
109→}
