178→/**
179→ * Detect if a transaction is likely a recurring subscription
180→ */
181→export function detectRecurringTransaction(description: string): {
182→  isRecurring: boolean;
183→  recurringName?: string;
184→} {
185→  const upperDesc = description.toUpperCase();
186→
187→  for (const { pattern, name } of RECURRING_PATTERNS) {
188→    if (pattern.test(upperDesc)) {
189→      return { isRecurring: true, recurringName: name };
190→    }
191→  }
192→
193→  return { isRecurring: false };
194→}
