229→export function detectInstallment(description: string): {
230→  isInstallment: boolean;
231→  currentInstallment?: number;
232→  totalInstallments?: number;
233→} {
234→  // Patterns for Brazilian credit card statements
235→  // Examples:
236→  // "EC *DEBORAEXCURSOES - Parcela 5/6"
237→  // "MP *MOBYDICK - Parcela 4/5"
238→  // "MERCADO*MULTIXIMPORTA - Parcela 4/12"
239→  // "SALLES TENIS SQUASH L - Parcela 4/6"
240→  // "RAIA DROGASIL SA - Parcela 2/3"
241→
242→  const numberedPatterns = [
243→    // "- Parcela X/Y" or "– Parcela X/Y" (most common in Brazilian card statements)
244→    /[-–]\s*Parcela\s+(\d+)\s*[\/\\]\s*(\d+)/i,
245→    // "Parcela X/Y" anywhere
246→    /Parcela\s+(\d+)\s*[\/\\]\s*(\d+)/i,
247→    // "PARC X/Y" or "PARC X DE Y"
248→    /PARC(?:ELA)?\s*(\d+)\s*(?:[\/\\]|DE)\s*(\d+)/i,
249→    // "X/Y" format (generic, check last)
250→    /(\d+)\s*[\/\\]\s*(\d+)/,
251→    // "X DE Y" format
252→    /(\d+)\s*DE\s*(\d+)/i,
253→  ];
254→
255→  for (const pattern of numberedPatterns) {
256→    const match = description.match(pattern);
257→    if (match) {
258→      const current = parseInt(match[1], 10);
259→      const total = parseInt(match[2], 10);
260→
261→      // Validate: current must be <= total, total must be > 1 (at least 2 installments)
262→      // and total should be reasonable (max 48 installments is common in Brazil)
263→      if (current > 0 && total > 1 && current <= total && total <= 48) {
264→        return {
265→          isInstallment: true,
266→          currentInstallment: current,
267→          totalInstallments: total,
268→        };
269→      }
270→    }
271→  }
272→
273→  // Detect "- Parcela" without number (common in C6 credit card statements)
274→  // This marks it as installment but without knowing which one
275→  if (/[-–]\s*Parcela\s*$/i.test(description) || /\bParcela\s*$/i.test(description)) {
276→    return { isInstallment: true };
277→  }
278→
279→  return { isInstallment: false };
280→}
