460→/**
461→ * Ensure global default investment categories exist.
462→ * This is called on first access to ensure defaults are available.
463→ * Uses in-memory caching to run only once per server instance.
464→ * Fails silently to not break the app if there are database issues.
465→ */
466→export async function ensureDefaultInvestmentCategories(): Promise<void> {
467→  if (investmentCategoriesInitialized) return;
468→
469→  try {
470→    // Single query to get all existing default categories
471→    const existing = await prisma.investmentCategory.findMany({
472→      where: { userId: null, isDefault: true },
473→      select: { name: true },
474→    });
475→
476→    const existingNames = new Set(existing.map((c) => c.name));
477→    const toCreate = defaultInvestmentCategories.filter(
478→      (c) => !existingNames.has(c.name)
479→    );
480→
481→    if (toCreate.length > 0) {
482→      await prisma.investmentCategory.createMany({
483→        data: toCreate.map((c) => ({
484→          name: c.name,
485→          color: c.color,
486→          icon: c.icon,
487→          isDefault: true,
488→          userId: null,
489→        })),
490→        skipDuplicates: true,
491→      });
492→    }
493→
494→    investmentCategoriesInitialized = true;
495→  } catch (error) {
496→    // Log but don't throw - categories can be fetched without defaults
497→    console.error("Failed to ensure default investment categories:", error);
498→    // Still mark as initialized to avoid repeated attempts
499→    investmentCategoriesInitialized = true;
500→  }
501→}
