 45→}
 46→
 47→interface BillTransaction {
 48→  id: string;
 49→  description: string;
 50→  amount: number;
 51→  date: string;
 52→  origin: string;
 53→  categoryId: string | null;
 54→  categoryName: string;
 55→  categoryColor: string;
 56→  isInstallment: boolean;
 57→  currentInstallment: number | null;
 58→}
 59→
 60→interface CarryoverInfo {
 61→  amount: number;
 62→  interest: number;
 63→  fromBill: string;
 64→  billPaymentId: string;
 65→}
 66→
 67→interface Bill {
 68→  label: string;
 69→  month: number;
 70→  year: number;
 71→  startDate: string;
 72→  endDate: string;
 73→  dueDate: string;
 74→  total: number;
 75→  transactionTotal: number;
 76→  carryover: CarryoverInfo | null;
 77→  transactionCount: number;
 78→  categories: BillCategory[];
