 89→export default function BillsPage() {
 90→  const [bills, setBills] = useState<Bill[]>([]);
 91→  const [origins, setOrigins] = useState<Origin[]>([]);
 92→  const [loading, setLoading] = useState(true);
 93→  const [closingDay, setClosingDay] = useState(13);
 94→  const [selectedOrigin, setSelectedOrigin] = useState<string>("");
 95→  const [expandedBill, setExpandedBill] = useState<number | null>(0);
 96→  const [showSettings, setShowSettings] = useState(false);
 97→  const [paymentModalOpen, setPaymentModalOpen] = useState(false);
 98→  const [selectedBillForPayment, setSelectedBillForPayment] = useState<Bill | null>(null);
 99→
100→  useEffect(() => {
101→    fetchBills();
102→  }, [closingDay, selectedOrigin]);
103→
104→  async function fetchBills() {
105→    setLoading(true);
106→    try {
107→      const params = new URLSearchParams({
108→        closingDay: closingDay.toString(),
109→      });
110→      if (selectedOrigin) {
111→        params.append("origin", selectedOrigin);
112→      }
113→
114→      const res = await fetch(`/api/bills?${params}`);
115→      const data = await res.json();
116→      setBills(data.bills || []);
117→      setOrigins(data.origins || []);
118→    } catch (error) {
119→      console.error("Error fetching bills:", error);
120→    } finally {
121→      setLoading(false);
122→    }
123→  }
124→
125→  function toggleBill(index: number) {
126→    setExpandedBill(expandedBill === index ? null : index);
127→  }
128→
129→  function formatPeriod(startDate: string, endDate: string) {
130→    const start = new Date(startDate);
131→    const end = new Date(endDate);
132→    return `${start.getDate().toString().padStart(2, "0")}/${(start.getMonth() + 1).toString().padStart(2, "0")} a ${end.getDate().toString().padStart(2, "0")}/${(end.getMonth() + 1).toString().padStart(2, "0")}`;
133→  }
134→
135→  function openPaymentModal(bill: Bill, e: React.MouseEvent) {
136→    e.stopPropagation();
137→    setSelectedBillForPayment(bill);
138→    setPaymentModalOpen(true);
139→  }
140→
141→  function handlePaymentSuccess() {
142→    fetchBills();
143→  }
144→
145→  const currentBill = bills[0];
146→  const totalLast6Months = bills.reduce((sum, b) => sum + b.total, 0);
147→  const averageBill = bills.length > 0 ? totalLast6Months / bills.length : 0;
148→
149→  return (
150→    <div className="space-y-6 px-4 md:px-6 overflow-x-hidden">
151→      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
