153→          <h1 className="text-2xl font-bold text-gray-900">Faturas</h1>
154→          <p className="text-gray-500 text-sm sm:text-base">
155→            Visualize seus gastos por ciclo de fatura do cartao
156→          </p>
157→        </div>
158→        <Button
159→          variant="outline"
160→          size="sm"
161→          onClick={() => setShowSettings(!showSettings)}
162→          className="w-full sm:w-auto min-h-[44px]"
163→        >
164→          <Settings2 className="h-4 w-4 mr-2" />
165→          Configurar
166→        </Button>
167→      </div>
168→
169→      {showSettings && (
170→        <Card>
171→          <CardContent className="pt-4">
172→            <div className="flex items-end gap-4">
173→              <div className="space-y-2">
174→                <Label htmlFor="closingDay">Dia do fechamento</Label>
175→                <Input
176→                  id="closingDay"
177→                  type="number"
178→                  min={1}
179→                  max={28}
180→                  value={closingDay}
181→                  onChange={(e) => setClosingDay(parseInt(e.target.value) || 13)}
182→                  className="w-24"
183→                />
184→              </div>
185→              <div className="space-y-2">
186→                <Label htmlFor="origin">Filtrar por cartao</Label>
187→                <Select
188→                  value={selectedOrigin || "all"}
189→                  onValueChange={(v) => setSelectedOrigin(v === "all" ? "" : v)}
190→                >
191→                  <SelectTrigger className="w-48">
192→                    <SelectValue placeholder="Todos os cartoes" />
193→                  </SelectTrigger>
194→                  <SelectContent>
