206→              </p>
207→            </div>
208→          </CardContent>
209→        </Card>
210→      )}
211→
212→      {/* Summary Cards */}
213→      <div className="grid gap-4 md:grid-cols-3">
214→        <Card>
215→          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
