                                    style={{ backgroundColor: t.categoryColor }}
                                  />
                                  <span className="text-sm">{t.categoryName}</span>
                                </div>
                              </TableCell>
                              <TableCell className="text-right font-medium text-red-600">
                                {formatCurrency(t.amount)}
                              </TableCell>
                            </TableRow>
                          ))}
