                    <span className="text-gray-500">{ocrProgress}%</span>
                  </div>
                  <Progress value={ocrProgress} className="h-2" />
                  <p className="text-xs text-gray-400">
                    O processamento de imagens pode levar alguns segundos
                  </p>
                </div>
              )}
            </div>
          </CardContent>
        </Card>
