                      </span>
                    )}
                    {expenseCount > 0 && (
                      <span className="flex items-center gap-1">
                        <ArrowUpCircle className="h-4 w-4 text-red-500" />
                        {expenseCount} despesa{expenseCount !== 1 ? 's' : ''}
                      </span>
