                            {t.isRecurring && (
                              <Badge variant="outline" className="text-xs bg-blue-50 text-blue-700 border-blue-200">
                                <RefreshCw className="h-3 w-3 mr-1" />
                                {t.recurringName || "Recorrente"}
                              </Badge>
