                                <ArrowDownCircle className="h-3 w-3 mr-1" />
                                Estorno
                              </Badge>
                            )}
                            {fileType === "ocr" && t.confidence !== undefined && (
                              getConfidenceBadge(t.confidence)
                            )}
                          </div>
                        </div>
                      </div>

                      {/* Expanded content */}
                      {isExpanded && (
                        <div className="mt-4 pt-3 border-t space-y-3">
                          {/* Category selector */}
                          <div>
                            <Label className="text-xs text-gray-500 mb-1 block">
                              Categoria
                            </Label>
                            <Select
                              value={t.categoryId || ""}
                              onValueChange={(value) => {
                                const tagMatch = value ? matchTag(t.description, value) : null;
                                updateTransaction(index, {
                                  categoryId: value || undefined,
                                  categoryTagId: tagMatch?.id,
                                  categoryTagName: tagMatch?.name,
                                });
                                if (value && value !== t.categoryId) {
                                  suggestRule(t.description, value);
                                  suggestTag(t.description, value);
                                }
                              }}
                            >
                              <SelectTrigger className="w-full">
                                <SelectValue placeholder="Selecione" />
                              </SelectTrigger>
                              <SelectContent>
                                {categories.map((c) => (
                                  <SelectItem key={c.id} value={c.id}>
                                    <div className="flex items-center gap-2">
                                      <div
                                        className="h-3 w-3 rounded-full"
                                        style={{ backgroundColor: c.color }}
                                      />
                                      {c.name}
                                    </div>
                                  </SelectItem>
                                ))}
                              </SelectContent>
                            </Select>
                          </div>

                          {/* Edit description for OCR */}
                          {fileType === "ocr" && (
                            <div>
                              <Label className="text-xs text-gray-500 mb-1 block">
                                Descricao
                              </Label>
                              {t.isEditing ? (
                                <div className="flex items-center gap-2">
                                  <Input
                                    value={t.editedDescription}
                                    onChange={(e) =>
                                      updateTransaction(index, {
                                        editedDescription: e.target.value,
                                      })
                                    }
                                    className="h-8"
                                  />
                                  <Button
                                    size="sm"
                                    variant="outline"
                                    onClick={() => saveEdit(index)}
                                  >
                                    OK
                                  </Button>
                                  <Button
                                    size="sm"
                                    variant="ghost"
                                    onClick={() => cancelEdit(index)}
                                  >
                                    X
                                  </Button>
                                </div>
                              ) : (
                                <Button
                                  size="sm"
                                  variant="outline"
                                  className="w-full"
                                  onClick={() => startEditing(index)}
                                >
                                  <Pencil className="h-3 w-3 mr-1" />
                                  Editar descricao
                                </Button>
                              )}
                            </div>
                          )}

                          {/* Actions */}
                          <div className="flex justify-end">
                            <Button
                              size="sm"
                              variant="ghost"
                              className="text-red-600 hover:text-red-700 hover:bg-red-50"
                              onClick={() => removeTransaction(index)}
                            >
                              <Trash2 className="h-4 w-4 mr-1" />
                              Remover
                            </Button>
                          </div>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>

              {/* Desktop Table View */}
              <div className="hidden md:block max-h-[500px] overflow-auto rounded-md border">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead className="w-12"></TableHead>
                      <TableHead>Data</TableHead>
                      {fileType === "ocr" && (
                        <TableHead className="w-20">Tipo</TableHead>
                      )}
                      <TableHead>Descrição</TableHead>
                      <TableHead>Categoria</TableHead>
                      {fileType === "ocr" && (
                        <TableHead className="w-20">Confiança</TableHead>
                      )}
                      <TableHead className="text-right">Valor</TableHead>
                      <TableHead className="w-12"></TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {transactions.map((t, index) => (
                      <TableRow
                        key={index}
                        className={t.selected ? "" : "opacity-50"}
                      >
                        <TableCell>
                          <input
                            type="checkbox"
                            checked={t.selected}
                            onChange={(e) =>
                              updateTransaction(index, {
                                selected: e.target.checked,
                              })
                            }
                            className="h-4 w-4"
                          />
                        </TableCell>
                        <TableCell className="whitespace-nowrap">
                          <div className="flex flex-col">
                            <span>{formatDate(t.date)}</span>
                            {t.isInstallment && t.originalDate && (
                              <span className="text-xs text-gray-400">
                                Compra: {formatDate(t.originalDate)}
                              </span>
                            )}
                          </div>
                        </TableCell>
                        {fileType === "ocr" && (
                          <TableCell>
                            {t.type === "INCOME" ? (
                              <Badge className="bg-green-100 text-green-800">
                                <ArrowDownCircle className="mr-1 h-3 w-3" />
                                Entrada
                              </Badge>
                            ) : t.type === "TRANSFER" ? (
                              <Badge className="bg-gray-100 text-gray-800">
                                <ArrowLeftRight className="mr-1 h-3 w-3" />
                                Transfer
                              </Badge>
                            ) : (
                              <Badge className="bg-red-100 text-red-800">
                                <ArrowUpCircle className="mr-1 h-3 w-3" />
                                Saida
                              </Badge>
                            )}
                          </TableCell>
                        )}
                        <TableCell>
                          {t.isEditing ? (
                            <div className="flex items-center gap-2">
                              <Input
                                value={t.editedDescription}
                                onChange={(e) =>
                                  updateTransaction(index, {
                                    editedDescription: e.target.value,
                                  })
                                }
                                className="h-8"
                              />
                              <Button
                                size="sm"
                                variant="outline"
                                onClick={() => saveEdit(index)}
                              >
                                OK
                              </Button>
                              <Button
                                size="sm"
                                variant="ghost"
                                onClick={() => cancelEdit(index)}
                              >
                                X
                              </Button>
                            </div>
                          ) : (
                            <div className="flex items-center gap-2">
                              <span className="flex-1">{t.description}</span>
                              {t.isDuplicate && (
                                <Badge variant="outline" className="text-xs bg-orange-50 text-orange-700 border-orange-200">
                                  <AlertTriangle className="h-3 w-3 mr-1" />
                                  Possivel duplicata
                                </Badge>
                              )}
                              {t.type === "TRANSFER" && (
                                <Badge variant="outline" className="text-xs bg-gray-100 text-gray-700 border-gray-300">
                                  <ArrowLeftRight className="h-3 w-3 mr-1" />
                                  Transferencia
                                </Badge>
                              )}
                              {t.isInstallment && (
                                <Badge variant="outline" className="text-xs bg-purple-50 text-purple-700 border-purple-200">
                                  <Repeat className="h-3 w-3 mr-1" />
                                  {t.currentInstallment && t.totalInstallments
                                    ? `Parcela ${t.currentInstallment}/${t.totalInstallments}`
                                    : "Parcela"}
                                </Badge>
                              )}
                              {t.isRelatedInstallment && t.relatedInstallmentInfo && (
                                <Badge
                                  variant="outline"
                                  className="text-xs bg-blue-50 text-blue-700 border-blue-200"
                                  title={`Continuacao de: ${t.relatedInstallmentInfo.relatedDescription}`}
                                >
                                  <Link2 className="h-3 w-3 mr-1" />
                                  Vinculada a {t.relatedInstallmentInfo.relatedInstallment}/{t.totalInstallments}
                                </Badge>
                              )}
                              {t.isRecurring && (
                                <Badge variant="outline" className="text-xs bg-blue-50 text-blue-700 border-blue-200">
                                  <RefreshCw className="h-3 w-3 mr-1" />
                                  Recorrente: {t.recurringName || "Recorrente"}
                                </Badge>
                              )}
                              {t.recurringAlreadyGenerated && (
                                <Badge variant="outline" className="text-xs bg-amber-50 text-amber-700 border-amber-200">
                                  <AlertTriangle className="h-3 w-3 mr-1" />
                                  Recorrente ja gerada
                                </Badge>
                              )}
                              {t.recurringMatchId && !t.recurringAlreadyGenerated && (
                                <Badge variant="outline" className="text-xs bg-blue-50 text-blue-700 border-blue-200">
                                  <Link2 className="h-3 w-3 mr-1" />
                                  Vincular a recorrente
                                </Badge>
                              )}
                              {t.categoryTagName && (
                                <Badge variant="outline" className="text-xs bg-teal-50 text-teal-700 border-teal-200">
                                  <Tag className="h-3 w-3 mr-1" />
                                  Tag: {t.categoryTagName}
                                </Badge>
                              )}
                              {t.specialType === "BILL_PAYMENT" && (
                                <Badge variant="outline" className="text-xs bg-amber-100 text-amber-800 border-amber-300" title={t.specialTypeWarning}>
                                  <CreditCard className="h-3 w-3 mr-1" />
                                  Pagamento Fatura
                                </Badge>
                              )}
                              {t.specialType === "FINANCING" && (
                                <Badge variant="outline" className="text-xs bg-red-100 text-red-800 border-red-300" title={t.specialTypeWarning}>
                                  <Receipt className="h-3 w-3 mr-1" />
                                  Parcelamento Fatura
                                </Badge>
                              )}
                              {t.specialType === "REFUND" && (
                                <Badge variant="outline" className="text-xs bg-green-100 text-green-800 border-green-300" title={t.specialTypeWarning}>
                                  <ArrowDownCircle className="h-3 w-3 mr-1" />
                                  Estorno
                                </Badge>
                              )}
                              {(t.specialType === "FEE" || t.specialType === "IOF" || t.specialType === "CURRENCY_SPREAD") && (
                                <Badge variant="outline" className="text-xs bg-gray-100 text-gray-700 border-gray-300" title={t.specialTypeWarning}>
                                  <Info className="h-3 w-3 mr-1" />
                                  {t.specialType === "FEE" ? "Taxa/Anuidade" : t.specialType === "IOF" ? "IOF" : "Cotacao"}
                                </Badge>
                              )}
                              {t.transactionKind && (
                                <Badge variant="secondary" className="text-xs">
                                  {t.transactionKind}
                                </Badge>
                              )}
                              {fileType === "ocr" && (
                                <Button
                                  size="sm"
                                  variant="ghost"
                                  className="h-6 w-6 p-0"
                                  onClick={() => startEditing(index)}
                                >
                                  <Pencil className="h-3 w-3" />
                                </Button>
                              )}
                            </div>
                          )}
                        </TableCell>
                        <TableCell>
                          <Select
                            value={t.categoryId || ""}
                            onValueChange={(value) => {
                              const tagMatch = value ? matchTag(t.description, value) : null;
                              updateTransaction(index, {
                                categoryId: value || undefined,
                                categoryTagId: tagMatch?.id,
                                categoryTagName: tagMatch?.name,
                              });
                              if (value && value !== t.categoryId) {
                                suggestRule(t.description, value);
                                suggestTag(t.description, value);
                              }
                            }}
                          >
                            <SelectTrigger className="w-40">
                              <SelectValue placeholder="Selecione" />
                            </SelectTrigger>
                            <SelectContent>
                              {categories.map((c) => (
                                <SelectItem key={c.id} value={c.id}>
                                  <div className="flex items-center gap-2">
                                    <div
                                      className="h-3 w-3 rounded-full"
                                      style={{ backgroundColor: c.color }}
                                    />
                                    {c.name}
                                  </div>
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </TableCell>
                        {fileType === "ocr" && (
                          <TableCell>{getConfidenceBadge(t.confidence)}</TableCell>
                        )}
                        <TableCell
                          className={`text-right font-medium ${
                            t.type === "INCOME"
                              ? "text-green-600"
                              : t.type === "TRANSFER"
                              ? "text-gray-400"
                              : "text-red-600"
                          }`}
                        >
                          {formatCurrency(t.amount)}
                        </TableCell>
                        <TableCell>
                          <Button
                            size="sm"
                            variant="ghost"
                            className="h-8 w-8 p-0 text-gray-400 hover:text-red-600"
                            onClick={() => removeTransaction(index)}
                            title="Remover transação"
                          >
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </div>
            </CardContent>
          </Card>

          <div className="flex gap-4">
            <Button variant="outline" onClick={resetForm}>
              Cancelar
            </Button>
            <Button onClick={handleImport} disabled={importing || selectedCount === 0}>
              {importing
                ? "Importando..."
                : `Importar ${selectedCount} transações`}
            </Button>
          </div>
        </>
      )}

      {step === "done" && (
        <Card>
          <CardContent className="pt-6">
            <div className="flex flex-col items-center justify-center py-12">
              <div className="rounded-full bg-green-100 p-4">
                <Check className="h-8 w-8 text-green-600" />
              </div>
              <h2 className="mt-4 text-xl font-semibold">
                Importação concluída!
              </h2>
              <p className="mt-2 text-gray-500">
                As transações foram importadas com sucesso.
              </p>
              <div className="mt-6 flex flex-col items-center gap-4">
                <div className="flex gap-4">
                  <Button variant="outline" onClick={resetForm}>
                    Importar mais
                  </Button>
                  <Button onClick={() => (window.location.href = "/transactions")}>
                    Ver transações
                  </Button>
                </div>
                {lastImportBatchId && (
                  <Button
                    variant="ghost"
                    className="text-red-600 hover:text-red-700 hover:bg-red-50"
                    onClick={async () => {
                      try {
                        const res = await fetch(`/api/import?batchId=${lastImportBatchId}`, {
                          method: "DELETE",
                        });
                        if (res.ok) {
                          const data = await res.json();
                          toast({
                            title: "Importação desfeita",
                            description: `${data.count} transações removidas`,
                          });
                          setLastImportBatchId(null);
                        } else {
                          throw new Error("Erro ao desfazer");
                        }
                      } catch {
                        toast({
                          title: "Erro",
                          description: "Não foi possível desfazer a importação",
                          variant: "destructive",
                        });
                      }
                    }}
                  >
                    <Trash2 className="h-4 w-4 mr-2" />
                    Desfazer importação
                  </Button>
                )}
              </div>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

