1→-- AlterTable
2→ALTER TABLE "Transaction" ADD COLUMN "importBatchId" TEXT;
3→
4→-- CreateIndex
5→CREATE INDEX "Transaction_userId_importBatchId_idx" ON "Transaction"("userId", "importBatchId");
