  1→import { NextRequest, NextResponse } from "next/server";
  2→import prisma from "@/lib/db";
  3→import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
  4→
  5→export async function GET(
  6→  request: NextRequest,
  7→  { params }: { params: Promise<{ id: string }> }
  8→) {
  9→  try {
 10→    const userId = await getAuthenticatedUserId();
 11→    const { id } = await params;
 12→    const transaction = await prisma.transaction.findFirst({
 13→      where: { id, userId },
 14→      include: {
 15→        category: true,
 16→        categoryTag: true,
 17→        installment: true,
 18→      },
 19→    });
 20→
 21→    if (!transaction) {
 22→      return NextResponse.json(
 23→        { error: "Transacao nao encontrada" },
 24→        { status: 404 }
 25→      );
 26→    }
 27→
 28→    return NextResponse.json(transaction);
 29→  } catch (error) {
 30→    if (error instanceof Error && error.message === "Unauthorized") {
 31→      return unauthorizedResponse();
 32→    }
 33→    console.error("Error fetching transaction:", error);
 34→    return NextResponse.json(
 35→      { error: "Erro ao buscar transacao" },
 36→      { status: 500 }
 37→    );
 38→  }
 39→}
 40→
 41→export async function PUT(
 42→  request: NextRequest,
 43→  { params }: { params: Promise<{ id: string }> }
 44→) {
 45→  try {
 46→    const userId = await getAuthenticatedUserId();
 47→    const { id } = await params;
 48→    const body = await request.json();
 49→    const {
 50→      description,
 51→      amount,
 52→      date,
 53→      type,
 54→      origin,
 55→      categoryId,
 56→      categoryTagId,
 57→      isFixed,
 58→      tags,
 59→      isInstallment,
 60→      currentInstallment,
 61→      totalInstallments,
 62→    } = body;
 63→
 64→    // Process tags - accept array or string, store as JSON string
 65→    const processedTags = tags
 66→      ? Array.isArray(tags)
 67→        ? JSON.stringify(tags)
 68→        : tags
 69→      : null;
 70→
 71→    // Verify transaction belongs to user before updating
 72→    const existingTransaction = await prisma.transaction.findFirst({
 73→      where: { id, userId },
 74→    });
 75→
 76→    if (!existingTransaction) {
 77→      return NextResponse.json(
 78→        { error: "Transacao nao encontrada" },
 79→        { status: 404 }
 80→      );
 81→    }
 82→
 83→    // Validate categoryTagId belongs to user and matches category
 84→    let validatedTagId: string | null | undefined = undefined;
 85→    if (categoryTagId !== undefined) {
 86→      if (categoryTagId === null || categoryTagId === "") {
 87→        validatedTagId = null;
 88→      } else {
 89→        const tag = await prisma.categoryTag.findFirst({
 90→          where: {
 91→            id: categoryTagId,
 92→            userId,
 93→            categoryId: categoryId || undefined,
 94→          },
 95→        });
 96→        validatedTagId = tag ? categoryTagId : null;
 97→      }
 98→    }
 99→
100→    const transaction = await prisma.transaction.update({
101→      where: { id },
102→      data: {
103→        description,
104→        amount: type === "EXPENSE" ? -Math.abs(amount) : Math.abs(amount),
105→        date: new Date(date + "T12:00:00"),
106→        type,
107→        origin,
108→        categoryId: categoryId || null,
109→        categoryTagId: validatedTagId !== undefined ? validatedTagId : undefined,
110→        isFixed: isFixed || false,
111→        tags: processedTags,
112→        isInstallment: isInstallment || false,
113→        currentInstallment: isInstallment ? currentInstallment : null,
114→        totalInstallments: isInstallment ? totalInstallments : null,
115→      },
116→      include: {
117→        category: true,
118→        categoryTag: true,
119→        installment: true,
120→      },
121→    });
122→
123→    return NextResponse.json(transaction);
124→  } catch (error) {
125→    if (error instanceof Error && error.message === "Unauthorized") {
126→      return unauthorizedResponse();
127→    }
128→    console.error("Error updating transaction:", error);
129→    return NextResponse.json(
130→      { error: "Erro ao atualizar transacao" },
131→      { status: 500 }
132→    );
133→  }
134→}
135→
136→export async function DELETE(
137→  request: NextRequest,
138→  { params }: { params: Promise<{ id: string }> }
139→) {
140→  try {
141→    const userId = await getAuthenticatedUserId();
142→    const { id } = await params;
143→    const searchParams = request.nextUrl.searchParams;
144→    const permanent = searchParams.get("permanent");
145→
146→    // Verify transaction belongs to user before deleting
147→    const existingTransaction = await prisma.transaction.findFirst({
148→      where: { id, userId },
149→    });
150→
151→    if (!existingTransaction) {
152→      return NextResponse.json(
153→        { error: "Transacao nao encontrada" },
154→        { status: 404 }
155→      );
156→    }
157→
158→    if (permanent === "true") {
159→      // Permanent delete
160→      await prisma.transaction.delete({
161→        where: { id },
162→      });
163→    } else {
164→      // Soft delete - set deletedAt timestamp
