 54→    54→// Detecta transacoes especiais de cartao de credito
 55→    55→function detectSpecialTransaction(description: string): { type: SpecialTransactionType; warning: string } | null {
 56→    56→  const upperDesc = description.toUpperCase();
 57→    57→
 58→    58→  // Pagamento de fatura (credito na fatura)
 59→    59→  if (
 60→    60→    upperDesc.includes("INCLUSAO DE PAGAMENTO") ||
 61→    61→    upperDesc.includes("PAGAMENTO RECEBIDO") ||
 62→    62→    upperDesc.includes("PAGTO RECEBIDO") ||
 63→    63→    upperDesc.includes("CREDITO PAGAMENTO") ||
 64→    64→    upperDesc.includes("PAGAMENTO FATURA") ||
 65→    65→    upperDesc.includes("PAG FATURA")
 66→    66→  ) {
 67→    67→    return {
 68→    68→      type: "BILL_PAYMENT",
 69→    69→      warning: "Este e um registro de pagamento da fatura anterior. Normalmente deve ser ignorado ou tratado como credito."
 70→    70→    };
 71→    71→  }
 72→    72→
 73→    73→  // Parcelamento de fatura (refinanciamento)
 74→    74→  if (
 75→    75→    upperDesc.includes("PARCELAMENTO DE FATURA") ||
 76→    76→    upperDesc.includes("PARCELAMENTO FATURA") ||
 77→    77→    upperDesc.includes("FATURA PARCELADA") ||
 78→    78→    upperDesc.includes("REPARCELAMENTO") ||
 79→    79→    upperDesc.includes("REFINANCIAMENTO")
 80→    80→  ) {
 81→    81→    return {
 82→    82→      type: "FINANCING",
 83→    83→      warning: "Este e um parcelamento/refinanciamento de divida. O valor original ja foi contabilizado anteriormente."
 84→    84→    };
 85→    85→  }
 86→    86→
 87→    87→  // Estorno
 88→    88→  if (
 89→    89→    upperDesc.includes("ESTORNO") ||
 90→    90→    upperDesc.includes("DEVOLUCAO") ||
 91→    91→    upperDesc.includes("CANCELAMENTO") ||
 92→    92→    upperDesc.includes("REEMBOLSO") ||
 93→    93→    upperDesc.includes("CHARGEBACK")
 94→    94→  ) {
 95→    95→    return {
 96→    96→      type: "REFUND",
 97→    97→      warning: "Este e um estorno/devolucao. O valor sera creditado (positivo)."
 98→    98→    };
 99→    99→  }
100→   100→
101→   101→  // Taxas e tarifas
102→   102→  if (
103→   103→    upperDesc.includes("ANUIDADE") ||
104→   104→    upperDesc.includes("TARIFA") ||
105→   105→    (upperDesc.includes("TAXA") && !upperDesc.includes("TAXAS DE"))
106→   106→  ) {
107→   107→    return {
108→   108→      type: "FEE",
109→   109→      warning: "Esta e uma tarifa/anuidade do cartao."
110→   110→    };
111→   111→  }
112→   112→
113→   113→  // IOF (transacoes internacionais)
114→   114→  if (
115→   115→    upperDesc.includes(" IOF") ||
116→   116→    upperDesc.includes("IOF ") ||
117→   117→    upperDesc.includes("IMPOSTO IOF")
118→   118→  ) {
119→   119→    return {
120→   120→      type: "IOF",
121→   121→      warning: "Este e o IOF de uma transacao internacional."
122→   122→    };
123→   123→  }
124→   124→
125→   125→  // Spread de cotacao (transacoes internacionais)
126→   126→  if (
127→   127→    upperDesc.includes("COTACAO") ||
128→   128→    upperDesc.includes("COTAÇÃO") ||
129→   129→    upperDesc.includes("SPREAD") ||
130→   130→    upperDesc.includes("CUUSD") ||
131→   131→    upperDesc.includes("CUEUR")
132→   132→  ) {
133→   133→    return {
134→   134→      type: "CURRENCY_SPREAD",
135→   135→      warning: "Este e o spread de cotacao de uma transacao internacional."
136→   136→    };
137→   137→  }
138→   138→
139→   139→  return null;
140→   140→}
