import { describe, it, expect, beforeEach, vi } from 'vitest'
import { NextRequest } from 'next/server'
import { testUser } from '../setup'

// Mock prisma with inline factory (vi.mock is hoisted)
vi.mock('@/lib/db', () => ({
  default: {
    recurringExpense: {
      findMany: vi.fn()
    },
    transaction: {
      create: vi.fn(),
      update: vi.fn()
    },
    billPayment: {
      findMany: vi.fn(),
      update: vi.fn()
    }
  }
}))

// Import route handlers and prisma mock after mocking
import { POST } from '@/app/api/import/route'
import prisma from '@/lib/db'

// Type assertion for mocked prisma
const mockPrisma = prisma as unknown as {
  recurringExpense: {
    findMany: ReturnType<typeof vi.fn>
  }
  transaction: {
    create: ReturnType<typeof vi.fn>
    update: ReturnType<typeof vi.fn>
  }
  billPayment: {
    findMany: ReturnType<typeof vi.fn>
    update: ReturnType<typeof vi.fn>
  }
}

// Helper to create NextRequest with JSON body
function createRequest(body: unknown): NextRequest {
  return new NextRequest(new URL('http://localhost:3000/api/import'), {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(body)
  })
}

// Helper to create a mock transaction response
function createMockTransaction(id: string, description: string, amount: number, date: string) {
  return {
    id,
    description,
    amount,
    date: new Date(date),
    type: 'EXPENSE',
    origin: 'Nubank',
    categoryId: null,
    category: null,
    isFixed: false,
    isInstallment: false,
    userId: testUser.id,
    recurringExpense: null
  }
}

describe('POST /api/import - Carryover Linking', () => {
  beforeEach(() => {
    vi.clearAllMocks()

    // Default mock returns - no recurring expenses
    mockPrisma.recurringExpense.findMany.mockResolvedValue([])
    // Default - no bill payments
    mockPrisma.billPayment.findMany.mockResolvedValue([])
  })

  describe('Basic import functionality', () => {
    it('should import transactions without carryover linking when no carryover patterns', async () => {
      const mockTransaction = createMockTransaction(
        'txn-1',
        'NETFLIX',
        -39.90,
        '2024-02-15'
      )
      mockPrisma.transaction.create.mockResolvedValue(mockTransaction)

      const request = createRequest({
        transactions: [
          { description: 'NETFLIX', amount: 39.90, date: '2024-02-15', type: 'EXPENSE' }
        ],
        origin: 'Nubank'
      })

      const response = await POST(request)
      const data = await response.json()

      expect(response.status).toBe(201)
      expect(data.count).toBe(1)
      expect(data.carryoverLinkedCount).toBe(0)
      expect(data.linkedCarryovers).toHaveLength(0)
      expect(mockPrisma.billPayment.update).not.toHaveBeenCalled()
    })

    it('should return error for invalid transactions', async () => {
      const request = createRequest({
        transactions: 'invalid'
      })

      const response = await POST(request)
      const data = await response.json()

      expect(response.status).toBe(400)
      expect(data.error).toBe('Transacoes invalidas')
    })
  })

  describe('Recurring expense matching', () => {
    it('should match autoGenerate=true recurring expenses during import', async () => {
      // Setup: recurring expense with autoGenerate=true and NO transaction for January
      mockPrisma.recurringExpense.findMany.mockResolvedValue([
        {
          id: 'rec-spotify',
          description: 'SPOTIFY',
          amount: -19.90,
          origin: 'Nubank',
          categoryId: 'cat-1',
          autoGenerate: true,
          isActive: true,
          userId: testUser.id,
          transactions: [], // No existing transaction for this month
        }
      ])

      const mockTransaction = {
        ...createMockTransaction('txn-spotify', 'EBN *SPOTIFY', -19.90, '2024-01-15'),
        isFixed: true,
        recurringExpenseId: 'rec-spotify',
        recurringExpense: { id: 'rec-spotify', description: 'SPOTIFY' },
      }
      mockPrisma.transaction.create.mockResolvedValue(mockTransaction)

      const request = createRequest({
        transactions: [
          { description: 'EBN *SPOTIFY', amount: 19.90, date: '2024-01-15', type: 'EXPENSE' }
        ],
        origin: 'Nubank'
      })

      const response = await POST(request)
      const data = await response.json()

      expect(response.status).toBe(201)
      expect(data.count).toBe(1)
      expect(data.linkedCount).toBe(1)

      // Verify transaction was created with recurringExpenseId
      expect(mockPrisma.transaction.create).toHaveBeenCalledWith(
        expect.objectContaining({
          data: expect.objectContaining({
            recurringExpenseId: 'rec-spotify',
            isFixed: true,
          })
        })
      )
    })

    it('should NOT match recurring that already has a transaction this month', async () => {
      mockPrisma.recurringExpense.findMany.mockResolvedValue([
        {
          id: 'rec-spotify',
          description: 'SPOTIFY',
          amount: -19.90,
          origin: 'Nubank',
          categoryId: 'cat-1',
          autoGenerate: true,
          isActive: true,
          userId: testUser.id,
          transactions: [
            { id: 'existing-txn', date: new Date('2024-01-05') } // Already has a transaction for Jan
          ],
        }
      ])

      const mockTransaction = createMockTransaction('txn-spotify-2', 'EBN *SPOTIFY', -19.90, '2024-01-15')
      mockPrisma.transaction.create.mockResolvedValue(mockTransaction)

      const request = createRequest({
        transactions: [
          { description: 'EBN *SPOTIFY', amount: 19.90, date: '2024-01-15', type: 'EXPENSE' }
        ],
        origin: 'Nubank'
      })

      const response = await POST(request)
      const data = await response.json()

      expect(response.status).toBe(201)
      expect(data.linkedCount).toBe(0)

      // Transaction should NOT be linked to recurring
      expect(mockPrisma.transaction.create).toHaveBeenCalledWith(
        expect.objectContaining({
          data: expect.objectContaining({
            recurringExpenseId: null,
            isFixed: false,
          })
        })
      )
    })

    it('should query recurring expenses WITHOUT autoGenerate filter', async () => {
      mockPrisma.recurringExpense.findMany.mockResolvedValue([])
      const mockTransaction = createMockTransaction('txn-1', 'SOMETHING', -50, '2024-01-15')
      mockPrisma.transaction.create.mockResolvedValue(mockTransaction)

      const request = createRequest({
        transactions: [
          { description: 'SOMETHING', amount: 50, date: '2024-01-15', type: 'EXPENSE' }
        ],
        origin: 'Nubank'
      })

      await POST(request)

      // The query should NOT have autoGenerate: false filter
      const findManyCall = mockPrisma.recurringExpense.findMany.mock.calls[0][0]
      expect(findManyCall.where).not.toHaveProperty('autoGenerate')
    })

    it('should filter out soft-deleted transactions when checking existing recurring', async () => {
      mockPrisma.recurringExpense.findMany.mockResolvedValue([])
      const mockTransaction = createMockTransaction('txn-1', 'SOMETHING', -50, '2024-01-15')
      mockPrisma.transaction.create.mockResolvedValue(mockTransaction)

      const request = createRequest({
        transactions: [
          { description: 'SOMETHING', amount: 50, date: '2024-01-15', type: 'EXPENSE' }
        ],
        origin: 'Nubank'
      })

      await POST(request)

      // The include should filter for deletedAt: null
      const findManyCall = mockPrisma.recurringExpense.findMany.mock.calls[0][0]
      expect(findManyCall.include.transactions.where).toEqual({ deletedAt: null })
    })
  })

  describe('Carryover detection and linking', () => {
    it('should detect and link carryover transaction that matches existing BillPayment', async () => {
      // Setup: BillPayment from January 2024 with R$ 2,000 carried
      const mockBillPayment = {
        id: 'bp-1',
        billMonth: 1, // January
        billYear: 2024,
        origin: 'Nubank',
        totalBillAmount: 5000,
        amountPaid: 3000,
        amountCarried: 2000,
        paymentType: 'PARTIAL',
        linkedTransactionId: null,
        carryoverTransactionId: null,
        interestRate: null,
        interestAmount: null,
        userId: testUser.id,
        createdAt: new Date()
      }

      mockPrisma.billPayment.findMany.mockResolvedValue([mockBillPayment])

      // Imported carryover transaction in February 2024 statement
      // Amount is R$ 2,150 (original R$ 2,000 + 7.5% interest)
      const carryoverTransaction = createMockTransaction(
        'txn-carryover-1',
        'SALDO ROTATIVO',
        -2150,
        '2024-02-10'
      )
      mockPrisma.transaction.create.mockResolvedValue(carryoverTransaction)
      mockPrisma.billPayment.update.mockResolvedValue({
        ...mockBillPayment,
        linkedTransactionId: carryoverTransaction.id,
        interestRate: 7.5,
